long long calculateMaxProfit(vector<int>& prices) {
    long long buy1 = LLONG_MIN;
    long long sell1 = 0;
    long long buy2 = LLONG_MIN;
    long long sell2 = 0;

    for (int price : prices) {
        // First transaction
        buy1 = max(buy1, (long long)-price);
        sell1 = max(sell1, buy1 + price);

        // Second transaction
        buy2 = max(buy2, sell1 - price);
        sell2 = max(sell2, buy2 + price);
    }
    return sell2;
}

