long long calculateMaxProfit(int n, int* prices) {
    long long buy1 = LLONG_MIN;
    long long sell1 = 0;
    long long buy2 = LLONG_MIN;
    long long sell2 = 0;

    for (int i = 0; i < n; i++) {
        int price = prices[i];

        // First transaction
        if (buy1 < -price) buy1 = -price;
        if (sell1 < buy1 + price) sell1 = buy1 + price;

        // Second transaction
        if (buy2 < sell1 - price) buy2 = sell1 - price;
        if (sell2 < buy2 + price) sell2 = buy2 + price;
    }
    return sell2;
}

